<?php
if (!function_exists('hr_t')) {
  function hr_t($key, $fallback = '') { return lang_text($key, $fallback); }
}
if (!function_exists('hr_h')) {
  function hr_h($key, $fallback = '') { return htmlspecialchars((string) hr_t($key, $fallback), ENT_QUOTES, 'UTF-8'); }
}
if (!function_exists('hr_js')) {
  function hr_js($key, $fallback = '') { return json_encode(hr_t($key, $fallback), JSON_HEX_TAG | JSON_HEX_APOS | JSON_HEX_AMP | JSON_HEX_QUOT); }
}
if (session_status() === PHP_SESSION_NONE) session_start();

function tpv_h($value){ return htmlspecialchars((string)$value, ENT_QUOTES, 'UTF-8'); }
function tpv_num($value, $dec = 0){ return number_format((float)$value, $dec, '.', ','); }
function tpv_valid_date($value, $fallback){ $value = trim((string)$value); return preg_match('/^\d{4}-\d{2}-\d{2}$/', $value) ? $value : $fallback; }
function tpv_in_placeholders($count){ return implode(',', array_fill(0, max(1, (int)$count), '?')); }
function tpv_rating_class($rating){ $rating=(string)$rating; $map=array('A'=>'success','B'=>'primary','C'=>'info','D'=>'warning','E'=>'danger'); return isset($map[$rating])?$map[$rating]:'default'; }
function tpv_status_class($status){ $status=(string)$status; $map=array('DRAFT'=>'default','ASSIGNED'=>'info','ACKNOWLEDGED'=>'primary','IN_REVIEW'=>'warning','COMPLETED'=>'success','SUBMITTED'=>'primary','MANAGER_REVIEW'=>'warning','APPROVED'=>'success','REJECTED'=>'danger','RETURNED'=>'warning','CANCELLED'=>'default'); return isset($map[$status])?$map[$status]:'default'; }
function tpv_workdays($from, $to){ $s=strtotime($from); $e=strtotime($to); if(!$s||!$e||$e<$s)return 0; $n=0; for($t=$s;$t<=$e;$t=strtotime('+1 day',$t)) if((int)date('N',$t)<=5)$n++; return $n; }

if (!defined('TEAM_PERFORMANCE_VIEW_INCLUDE')) define('TEAM_PERFORMANCE_VIEW_INCLUDE', true);
require_once __DIR__ . '/team_performance_action.php';

$today = date('Y-m-d');
$from = tpv_valid_date(isset($_GET['tgl_awal']) ? $_GET['tgl_awal'] : '', date('Y-m-01'));
$to = tpv_valid_date(isset($_GET['tgl_akhir']) ? $_GET['tgl_akhir'] : '', $today);
if (strtotime($from) > strtotime($to)) $from = $to;
$filterEmployee = isset($_GET['employee_id']) ? (int)$_GET['employee_id'] : 0;
$filterDept = isset($_GET['department_code']) ? trim($_GET['department_code']) : '';
$filterRating = isset($_GET['final_rating']) ? trim($_GET['final_rating']) : '';
$filterStatus = isset($_GET['appraisal_status']) ? trim($_GET['appraisal_status']) : '';
$keyword = isset($_GET['keyword']) ? trim($_GET['keyword']) : '';

list($manager, $subIds) = tpa_manager_scope($db);
$subordinates = array();
if ($manager) {
  $stmtSub = $db->query("SELECT e.*, d.nm_dept, jt.job_title_name FROM erp_employee_master e LEFT JOIN dept d ON d.kd_dept=e.department_code LEFT JOIN erp_job_title jt ON jt.id=e.job_title_id WHERE e.manager_employee_id=? ORDER BY e.department_code,e.full_name", array((int)$manager->id));
  $subordinates = $stmtSub ? $stmtSub->fetchAll(PDO::FETCH_OBJ) : array();
}
$f = array('from'=>$from,'to'=>$to,'employee_id'=>$filterEmployee,'department_code'=>$filterDept,'final_rating'=>$filterRating,'appraisal_status'=>$filterStatus,'keyword'=>$keyword);
$rows = !empty($subIds) ? tpa_team_rows($db, $subIds, $f) : array();

$summary = array('team'=>count($subordinates),'attendance_records'=>0,'present_days'=>0,'late_count'=>0,'late_minutes'=>0,'actual_hours'=>0,'approved_ot'=>0,'leave_days'=>0,'avg_score'=>0,'rated'=>0,'pip'=>0);
$ratingChart = array(); $statusChart = array(); $scoreCategories = array(); $scoreData = array(); $lateData = array(); $presenceData = array();
$expectedSlots = tpv_workdays($from, $to);
foreach ($rows as $r) {
  $summary['attendance_records'] += (float)$r->attendance_records;
  $summary['present_days'] += (float)$r->present_days;
  $summary['late_count'] += (float)$r->late_count;
  $summary['late_minutes'] += (float)$r->late_minutes;
  $summary['actual_hours'] += (float)$r->actual_hours;
  $summary['approved_ot'] += (float)$r->approved_ot_hours;
  $summary['leave_days'] += (float)$r->leave_days_total;
  if ($r->final_score !== null && (float)$r->final_score > 0) { $summary['avg_score'] += (float)$r->final_score; $summary['rated']++; }
  if ($r->improvement_required === 'Y') $summary['pip']++;
  $rating = $r->final_rating ?: 'NO_RATING';
  if (!isset($ratingChart[$rating])) $ratingChart[$rating]=0; $ratingChart[$rating]++;
  $status = $r->appraisal_status ?: 'NO_APPRAISAL';
  if (!isset($statusChart[$status])) $statusChart[$status]=0; $statusChart[$status]++;
  $scoreCategories[] = $r->employee_no.' - '.$r->full_name;
  $scoreData[] = (float)$r->final_score;
  $lateData[] = (float)$r->late_minutes;
  $presenceData[] = $expectedSlots > 0 ? round(((float)$r->present_days / $expectedSlots) * 100, 1) : 0;
}
$summary['avg_score'] = $summary['rated'] ? round($summary['avg_score'] / $summary['rated'], 2) : 0;
$presenceRate = ($expectedSlots * max(1, $summary['team'])) > 0 ? round(($summary['present_days'] / ($expectedSlots * max(1, $summary['team']))) * 100, 1) : 0;
$ratingSeries = array(); foreach($ratingChart as $k=>$v) $ratingSeries[] = array($k, (int)$v);
$statusSeries = array(); foreach($statusChart as $k=>$v) $statusSeries[] = array($k, (int)$v);
$photoUrl = $manager ? erpkb_user_photo_url(isset($manager->foto_user) ? $manager->foto_user : '', 'back_profil_foto') : base_admin().'assets/dist/img/default-user-neutral.svg';
?>
<style>
