gn:middle;font-size:12px}.tp-empty{padding:24px;border:1px dashed #cbd5e1;border-radius:18px;background:#f8fafc;color:#475569}.tp-action{white-space:nowrap}.tp-score{font-size:22px;font-weight:800;color:#0f172a}
