  <div class="tp-hero"><div class="row"><div class="col-md-8"><div class="tp-profile"><img class="tp-photo" src="<?=tpv_h($photoUrl);?>" alt="Manager"><div><h1>Team Performance Cockpit</h1><p><?= $manager ? tpv_h($manager->employee_no.' - '.$manager->full_name) : 'Manager belum terhubung ke employee master'; ?><?= $manager && $manager->department_code ? ' | '.tpv_h($manager->department_code) : ''; ?></p><p>Gabungan KPI/appraisal, attendance discipline, overtime, dan leave untuk membaca kondisi performa bawahan.</p></div></div></div><div class="col-md-4 text-right" style="position:relative;z-index:1"><a class="btn btn-success" href="<?=base_admin();?>modul/team_performance/team_performance_action.php?act=export&<?=http_build_query($_GET);?>"><i class="fa fa-file-excel-o"></i> <?=hr_h('common_export_excel', 'Export Excel');?></a></div></div></div>
  <?php if (!$manager) { ?><div class="tp-empty"><b>Employee profile manager belum ditemukan.</b><br>User login ini belum tersambung ke `erp_employee_master.user_id`.</div><?php } elseif (empty($subordinates)) { ?><div class="tp-empty"><b>Belum ada bawahan langsung.</b><br>Isi `manager_employee_id` di Employee Master agar data performance team muncul.</div><?php } else { ?>
  <div class="box tp-filter"><div class="box-body"><form method="get" class="form-horizontal"><div class="form-group"><label class="col-lg-1 control-label"><?=hr_h('hr_date', 'Date');?></label><div class="col-lg-2"><input name="tgl_awal" class="form-control tp-date" value="<?=tpv_h($from);?>"></div><div class="col-lg-2"><input name="tgl_akhir" class="form-control tp-date" value="<?=tpv_h($to);?>"></div><label class="col-lg-1 control-label"><?=hr_h('hr_employee', 'Employee');?></label><div class="col-lg-3"><select name="employee_id" class="form-control select2-basic"><option value="">All Team Member</option><?php foreach($subordinates as $s){ ?><option value="<?=$s->id;?>" <?=$filterEmployee===(int)$s->id?'selected':'';?>><?=tpv_h($s->employee_no.' - '.$s->full_name);?></option><?php } ?></select></div><label class="col-lg-1 control-label"><?=hr_h('hr_rating', 'Rating');?></label><div class="col-lg-2"><select name="final_rating" class="form-control select2-basic"><option value="">All</option><?php foreach(array('A','B','C','D','E') as $r){ ?><option value="<?=$r;?>" <?=$filterRating===$r?'selected':'';?>><?=$r;?></option><?php } ?></select></div></div><div class="form-group"><label class="col-lg-1 control-label">Dept</label><div class="col-lg-2"><select name="department_code" class="form-control select2-basic"><option value="">All Department</option><?php $seen=array(); foreach($subordinates as $s){ if($s->department_code && !isset($seen[$s->department_code])){ $seen[$s->department_code]=1; ?><option value="<?=tpv_h($s->department_code);?>" <?=$filterDept===$s->department_code?'selected':'';?>><?=tpv_h($s->department_code.' - '.$s->nm_dept);?></option><?php }} ?></select></div><label class="col-lg-1 control-label"><?=hr_h('common_status', 'Status');?></label><div class="col-lg-2"><select name="appraisal_status" class="form-control select2-basic"><option value="">All</option><?php foreach(array('DRAFT','SELF_ASSESSED','MANAGER_REVIEW','SUBMITTED','APPROVED','REJECTED','RETURNED','CANCELLED') as $s){ ?><option value="<?=$s;?>" <?=$filterStatus===$s?'selected':'';?>><?=$s;?></option><?php } ?></select></div><label class="col-lg-1 control-label"><?=hr_h('common_search', 'Search');?></label><div class="col-lg-3"><input name="keyword" class="form-control" value="<?=tpv_h($keyword);?>" placeholder="Employee, dept, position"></div><div class="col-lg-2"><button class="btn btn-primary"><i class="fa fa-filter"></i> <?=hr_h('common_filter', 'Filter');?></button> <a class="btn btn-default" href="<?=base_index();?>team-performance"><i class="fa fa-refresh"></i></a></div></div></form></div></div>
  <div class="row"><div class="col-md-2 col-sm-6"><div class="tp-kpi"><i class="fa fa-users"></i><span>Team</span><strong><?=tpv_num($summary['team']);?></strong><small>Bawahan langsung</small></div></div><div class="col-md-2 col-sm-6"><div class="tp-kpi"><i class="fa fa-star green"></i><span>Avg Score</span><strong><?=tpv_num($summary['avg_score'],2);?></strong><small><?=tpv_num($summary['rated']);?> employee rated</small></div></div><div class="col-md-2 col-sm-6"><div class="tp-kpi"><i class="fa fa-calendar-check-o green"></i><span>Presence Rate</span><strong><?=tpv_num($presenceRate,1);?>%</strong><small><?=tpv_num($summary['present_days']);?> present days</small></div></div><div class="col-md-2 col-sm-6"><div class="tp-kpi"><i class="fa fa-clock-o orange"></i><span>Late Minutes</span><strong><?=tpv_num($summary['late_minutes']);?></strong><small><?=tpv_num($summary['late_count']);?> late records</small></div></div><div class="col-md-2 col-sm-6"><div class="tp-kpi"><i class="fa fa-hourglass-half"></i><span>Approved OT</span><strong><?=tpv_num($summary['approved_ot'],1);?></strong><small>Jam lembur approved</small></div></div><div class="col-md-2 col-sm-6"><div class="tp-kpi"><i class="fa fa-warning red"></i><span>PIP</span><strong><?=tpv_num($summary['pip']);?></strong><small>Improvement required</small></div></div></div>
  <div class="row"><div class="col-md-5"><div class="box tp-card"><div class="box-header"><h3 class="box-title">Score vs Presence</h3></div><div class="box-body"><div id="tp_score_chart" class="tp-chart"></div></div></div></div><div class="col-md-4"><div class="box tp-card"><div class="box-header"><h3 class="box-title">Late Minutes</h3></div><div class="box-body"><div id="tp_late_chart" class="tp-chart"></div></div></div></div><div class="col-md-3"><div class="box tp-card"><div class="box-header"><h3 class="box-title"><?=hr_h('hr_rating', 'Rating');?></h3></div><div class="box-body"><div id="tp_rating_chart" class="tp-chart-sm"></div></div></div></div></div>
  <div class="box tp-card"><div class="box-header"><h3 class="box-title"><i class="fa fa-list"></i> Team Performance Detail</h3></div><div class="box-body table-responsive"><div class="alert alert-warning error_data_delete" style="display:none"><button class="close hide_alert_notif">&times;</button><span class="isi_warning_delete"></span></div><table id="tp_table" class="table table-bordered table-striped tp-table" style="width:100%"><thead><tr><th><?=hr_h('hr_employee', 'Employee');?></th><th><?=hr_h('hr_attendance', 'Attendance');?></th><th>Late / Leave / OT</th><th>KPI Assignment</th><th>Appraisal</th><th>Recommendation</th><th><?=hr_h('common_action', 'Action');?></th></tr></thead><tbody><?php foreach($rows as $r){ ?><tr><td><b><?=tpv_h($r->employee_no);?></b><br><?=tpv_h($r->full_name);?><br><small><?=tpv_h(($r->department_code?:'-').' - '.($r->nm_dept?:'-'));?></small></td><td>Present <b><?=tpv_num($r->present_days);?></b><br>Absence <?=tpv_num($r->absence_days);?> | Sick <?=tpv_num($r->sick_days);?><br><small>Actual <?=tpv_num($r->actual_hours,1);?> h</small></td><td>Late <b><?=tpv_num($r->late_minutes);?></b> min<br>Leave <?=tpv_num($r->leave_days_total,1);?> days<br>Approved OT <?=tpv_num($r->approved_ot_hours,1);?> h</td><td><b><?=tpv_h($r->employee_kpi_no ?: '-');?></b><br><span class="label label-<?=tpv_status_class($r->target_status);?>"><?=tpv_h($r->target_status ?: '-');?></span><br><small>Weight <?=tpv_num($r->total_weight,2);?>%</small></td><td><span class="tp-score"><?=tpv_num($r->final_score,2);?></span> <span class="label label-<?=tpv_rating_class($r->final_rating);?>"><?=tpv_h($r->final_rating ?: '-');?></span><br><small>KPI <?=tpv_num($r->manager_kpi_score,2);?> | Comp <?=tpv_num($r->competency_score,2);?> | Beh <?=tpv_num($r->behavior_score,2);?></small><br><span class="label label-<?=tpv_status_class($r->appraisal_status);?>"><?=tpv_h($r->appraisal_status ?: '-');?></span></td><td><?=tpv_h($r->reward_recommendation ?: '-');?><br><small><?=tpv_h($r->improvement_required==='Y'?'Improvement required':'No PIP');?></small></td><td class="tp-action"><button class="btn btn-info btn-xs btn-tp-detail" data-id="<?=(int)$r->employee_id;?>"><i class="fa fa-eye"></i></button></td></tr><?php } ?></tbody></table></div></div>
