<script>
function tpError(m){$('.isi_warning_delete').text(m||'Team Performance gagal diproses.');$('.error_data_delete').fadeIn();}
$(function(){if($.fn.datepicker){$('.tp-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('.select2-basic').select2({width:'100%',allowClear:true});}if($.fn.DataTable){$('#tp_table').DataTable({pageLength:25,order:[[4,'desc']],columnDefs:[{targets:[6],orderable:false}]});}$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});$(document).on('click','.btn-tp-detail',function(){$.post('<?=base_admin();?>modul/team_performance/team_performance_action.php?act=detail',{employee_id:$(this).data('id'),tgl_awal:'<?=tpv_h($from);?>',tgl_akhir:'<?=tpv_h($to);?>'},function(html){$('#tp_detail_body').html(html);$('#modal_tp_detail').modal('show');}).fail(function(xhr){tpError(xhr.responseText);});});if(typeof Highcharts!=='undefined'&&document.getElementById('tp_score_chart')){Highcharts.chart('tp_score_chart',{chart:{zoomType:'xy'},title:{text:null},xAxis:{categories:<?=json_encode($scoreCategories);?>},yAxis:[{title:{text:'Score / Presence %'},max:100}],tooltip:{shared:true},credits:{enabled:false},series:[{name:'Final Score',type:'column',data:<?=json_encode($scoreData);?>,color:'#2563eb'},{name:'Presence %',type:'spline',data:<?=json_encode($presenceData);?>,color:'#0f766e'}]});Highcharts.chart('tp_late_chart',{chart:{type:'bar'},title:{text:null},xAxis:{categories:<?=json_encode($scoreCategories);?>},yAxis:{title:{text:'Minutes'}},legend:{enabled:false},credits:{enabled:false},series:[{name:'Late Minutes',data:<?=json_encode($lateData);?>,color:'#f97316'}]});Highcharts.chart('tp_rating_chart',{chart:{type:'pie'},title:{text:null},credits:{enabled:false},plotOptions:{pie:{innerSize:'58%',dataLabels:{enabled:true,format:'{point.name}<br>{point.y}'}}},series:[{name:'Rating',data:<?=json_encode($ratingSeries);?>}]});}});
</script>
